// 食物类
class Food {
    constructor(canvas, snake) {
        this.canvas = canvas;
        this.snake = snake;
        this.size = 20;
        this.color = '#ff4757';
        this.position = this.generatePosition();
    }

    generatePosition() {
        let position;
        let valid = false;
        while (!valid) {
            position = {
                x: Math.floor(Math.random() * (this.canvas.width / this.size)) * this.size,
                y: Math.floor(Math.random() * (this.canvas.height / this.size)) * this.size
            };
            // 确保食物不会生成在蛇身上
            valid = !this.snake.body.some(segment => 
                segment.x === position.x && segment.y === position.y
            );
