// 游戏配置常量
const CONFIG = {
    GRID_SIZE: 20,
    CANVAS_WIDTH: 600,
    CANVAS_HEIGHT: 600,
    INITIAL_SPEED: 150,
    SPEED_DECREMENT: 5,
    MIN_SPEED: 50,
    COLORS: {
        SNAKE_HEAD: '#4CAF50',
        SNAKE_BODY: '#8BC34A',
        FOOD: '#FF5722',
        GRID: '#e0e0e0',
        BACKGROUND: '#f0f0f0'
    }
};

// 蛇类
class Snake {
    constructor() {
        this.reset();
    }

    reset() {
        this.body = [
            {x: 10, y: 10},
            {x: 9, y: 10},
            {x: 8, y: 10}
        ];
        this.direction = {x: 1, y: 0};
        this.nextDirection = {x: 1, y: 0};
        this.growPending = 0;
    }

    changeDirection(x, y) {
        // 防止反向移动
        if (this.direction.x === -x && this.direction.y === -y) return;
        this.nextDirection = {x, y};
    }

    move() {
        this.direction = this.nextDirection;
        const head = {x: this.body[0].x + this.direction.x, y: this.body[0].y + this.direction.y};

        this.body.unshift(head);

        if (this.growPending > 0) {
            this.growPending--;
        } else {
            this.body.pop();
        }

        return head;
    }

    checkCollision() {
        const head = this.body[0];

        // 检查墙壁碰撞
        if (head.x < 0 || head.x >= CONFIG.CANVAS_WIDTH / CONFIG.GRID_SIZE ||
            head.y < 0 || head.y >= CONFIG.CANVAS_HEIGHT / CONFIG.GRID_SIZE) {
            return true;
        }

        // 检查自身碰撞
        for (let i = 1; i < this.body.length; i++) {
            if (head.x === this.body[i].x && head.y === this.body[i].y) {
                return true;
            }
        }

        return false;
    }

    grow() {
        this.growPending++;
    }

    getLength() {
        return this.body.length;
    }

    getHead() {
        return this.body[0];
    }

    getBody() {
        return this.body;
    }
}

// 食物类
class Food {
    constructor() {
        this.position = {x: 0, y: 0};
        this.generate();
    }

    generate(snakeBody = []) {
        let validPosition = false;
        while (!validPosition) {
            this.position = {
                x: Math.floor(Math.random() * (CONFIG.CANVAS_WIDTH / CONFIG.GRID_SIZE)),
                y: Math.floor(Math.random() * (CONFIG.CANVAS_HEIGHT / CONFIG.GRID_SIZE))
            };

            // 确保食物不会生成在蛇身上
            validPosition = !snakeBody.some(segment => 
                segment.x === this.position.x && segment.y === this.position.y
            );
        }
    }

    getPosition() {
        return this.position;
    }
}

// 游戏主类
class Game {
    constructor() {
        this.canvas = document.getElementById('gameCanvas');
        this.ctx = this.canvas.getContext('2d');
        this.snake = new Snake();
        this.food = new Food();

        this.score = 0;
        this.highScore = localStorage.getItem('snakeHighScore') || 0;
        this.gameSpeed = CONFIG.INITIAL_SPEED;
        this.isRunning = false;
        this.isPaused = false;
        this.gameLoopId = null;

        this.initUI();
        this.bindEvents();
        this.draw();
    }

    initUI() {
        document.getElementById('score').textContent = '0';
        document.getElementById('highScore').textContent = this.highScore;
        document.getElementById('snakeLength').textContent = '3';
    }

    bindEvents() {
        document.addEventListener('keydown', (e) => this.handleInput(e));

        document.getElementById('startBtn').addEventListener('click', () => this.start());
        document.getElementById('resumeBtn').addEventListener('click', () => this.resume());
        document.getElementById('restartBtn').addEventListener('click', () => this.restart());
        document.getElementById('pauseBtn').addEventListener('click', () => this.togglePause());
        document.getElementById('resetBtn').addEventListener('click', () => this.reset());
    }

    handleInput(e) {
        if (!this.isRunning && e.key === 'Enter') {
            this.start();
            return;
        }

        if (this.isPaused && e.key === ' ') {
            this.resume();
            return;
        }

        if (!this.isPaused && this.isRunning) {
            switch (e.key) {
                case 'ArrowUp':
                    this.snake.changeDirection(0, -1);
                    break;
                case 'ArrowDown':
                    this.snake.changeDirection(0, 1);
                    break;
                case 'ArrowLeft':
                    this.snake.changeDirection(-1, 0);
                    break;
                case 'ArrowRight':
                    this.snake.changeDirection(1, 0);
                    break;
                case ' ':
                    this.togglePause();
                    break;
            }
        }
    }

    start() {
        this.snake.reset();
        this.food.generate();
        this.score = 0;
        this.gameSpeed = CONFIG.INITIAL_SPEED;
        this.isRunning = true;
        this.isPaused = false;

        this.updateUI();
        this.hideOverlays();
        this.gameLoop();
    }

    resume() {
        this.isPaused = false;
        this.hideOverlays();
        this.gameLoop();
    }

    togglePause() {
        if (!this.isRunning) return;

        this.isPaused = !this.isPaused;

        if (this.isPaused) {
            this.showOverlay('pauseScreen');
        } else {
            this.hideOverlays();
            this.gameLoop();
        }
    }

    restart() {
        this.start();
    }

    reset() {
        this.isRunning = false;
        this.isPaused = false;
        this.snake.reset();
        this.food.generate();
        this.score = 0;
        this.gameSpeed = CONFIG.INITIAL_SPEED;
        this.updateUI();
        this.hideOverlays();
        this.draw();
    }

    gameOver() {
        this.isRunning = false;
        this.showOverlay('gameOverScreen');
        document.getElementById('finalScore').textContent = this.score;

        if (this.score > this.highScore) {
            this.highScore = this.score;
            localStorage.setItem('snakeHighScore', this.highScore);
            document.getElementById('highScore').textContent = this.highScore;
        }
    }

    gameLoop() {
        if (!this.isRunning || this.isPaused) return;

        this.update();
        this.draw();

        this.gameLoopId = setTimeout(() => {
            requestAnimationFrame(() => this.gameLoop());
        }, this.gameSpeed);
    }

    update() {
        const head = this.snake.move();

        // 检查碰撞
        if (this.snake.checkCollision()) {
            this.gameOver();
            return;
        }

        // 检查是否吃到食物
        const foodPos = this.food.getPosition();
        if (head.x === foodPos.x && head.y === foodPos.y) {
            this.snake.grow();
            this.score += 10;
            this.food.generate(this.snake.getBody());

            // 增加难度
            if (this.score % 100 === 0 && this.gameSpeed > CONFIG.MIN_SPEED) {
                this.gameSpeed -= CONFIG.SPEED_DECREMENT;
            }

            this.updateUI();
        }
    }

    draw() {
        // 清空画布
        this.ctx.fillStyle = CONFIG.COLORS.BACKGROUND;
        this.ctx.fillRect(0, 0, CONFIG.CANVAS_WIDTH, CONFIG.CANVAS_HEIGHT);

        // 绘制网格
        this.drawGrid();

        // 绘制食物
        this.drawFood();

        // 绘制蛇
        this.drawSnake();
    }

    drawGrid() {
        this.ctx.strokeStyle = CONFIG.COLORS.GRID;
        this.ctx.lineWidth = 1;

        for (let x = 0; x <= CONFIG.CANVAS_WIDTH; x += CONFIG.GRID_SIZE) {
            this.ctx.beginPath();
            this.ctx.moveTo(x, 0);
            this.ctx.lineTo(x, CONFIG.CANVAS_HEIGHT);
            this.ctx.stroke();
        }

        for (let y = 0; y <= CONFIG.CANVAS_HEIGHT; y += CONFIG.GRID_SIZE) {
            this.ctx.beginPath();
            this.ctx.moveTo(0, y);
            this.ctx.lineTo(CONFIG.CANVAS_WIDTH, y);
            this.ctx.stroke();
        }
    }

    drawFood() {
        const pos = this.food.getPosition();
        const x = pos.x * CONFIG.GRID_SIZE;
        const y = pos.y * CONFIG.GRID_SIZE;

        // 绘制圆形食物
        this.ctx.fillStyle = CONFIG.COLORS.FOOD;
        this.ctx.beginPath();
        this.ctx.arc(x + CONFIG.GRID_SIZE / 2, y + CONFIG.GRID_SIZE / 2, CONFIG.GRID_SIZE / 2 - 2, 0, Math.PI * 2);
        this.ctx.fill();

        // 添加阴影效果
        this.ctx.shadowColor = CONFIG.COLORS.FOOD;
        this.ctx.shadowBlur = 10;
        this.ctx.fill();
        this.ctx.shadowBlur = 0;
    }

    drawSnake() {
        const body = this.snake.getBody();

        body.forEach((segment, index) => {
            const x = segment.x * CONFIG.GRID_SIZE;
            const y = segment.y * CONFIG.GRID_SIZE;

            // 蛇头颜色不同
            this.ctx.fillStyle = index === 0 ? CONFIG.COLORS.SNAKE_HEAD : CONFIG.COLORS.SNAKE_BODY;

            // 绘制圆角矩形
            this.roundRect(x + 1, y + 1, CONFIG.GRID_SIZE - 2, CONFIG.GRID_SIZE - 2, 4);
            this.ctx.fill();

            // 蛇头添加眼睛
            if (index === 0) {
                this.drawSnakeEyes(x, y);
            }
        });
    }

    roundRect(x, y, width, height, radius) {
        this.ctx.beginPath();
        this.ctx.moveTo(x + radius, y);
        this.ctx.lineTo(x + width - radius, y);
        this.ctx.quadraticCurveTo(x + width, y, x + width, y + radius);
        this.ctx.lineTo(x + width, y + height - radius);
        this.ctx.quadraticCurveTo(x + width, y + height, x + width - radius, y + height);
        this.ctx.lineTo(x + radius, y + height);
        this.ctx.quadraticCurveTo(x, y + height, x, y + height - radius);
        this.ctx.lineTo(x, y + radius);
        this.ctx.quadraticCurveTo(x, y, x + radius, y);
        this.ctx.closePath();
    }

    drawSnakeEyes(x, y) {
        this.ctx.fillStyle = 'white';
        const headX = x + CONFIG.GRID_SIZE / 2;
        const headY = y + CONFIG.GRID_SIZE / 2;

        // 根据方向绘制眼睛
        const eyeOffset = 4;
        const eyeSize = 3;

        if (this.snake.direction.x === 1) { // 向右
            this.ctx.beginPath();
            this.ctx.arc(headX + 4, headY - 4, eyeSize, 0, Math.PI * 2);
            this.ctx.arc(headX + 4, headY + 4, eyeSize, 0, Math.PI * 2);
            this.ctx.fill();
        } else if (this.snake.direction.x === -1) { // 向左
            this.ctx.beginPath();
            this.ctx.arc(headX - 4, headY - 4, eyeSize, 0, Math.PI * 2);
            this.ctx.arc(headX - 4, headY + 4, eyeSize, 0, Math.PI * 2);
            this.ctx.fill();
        } else if (this.snake.direction.y === -1) { // 向上
            this.ctx.beginPath();
            this.ctx.arc(headX - 4, headY - 4, eyeSize, 0, Math.PI * 2);
            this.ctx.arc(headX + 4, headY - 4, eyeSize, 0, Math.PI * 2);
            this.ctx.fill();
        } else if (this.snake.direction.y === 1) { // 向下
            this.ctx.beginPath();
            this.ctx.arc(headX - 4, headY + 4, eyeSize, 0, Math.PI * 2);
            this.ctx.arc(headX + 4, headY + 4, eyeSize, 0, Math.PI * 2);
            this.ctx.fill();
        }
    }

    updateUI() {
        document.getElementById('score').textContent = this.score;
        document.getElementById('snakeLength').textContent = this.snake.getLength();
        document.getElementById('highScore').textContent = this.highScore;
    }

    showOverlay(id) {
        document.querySelectorAll('.overlay').forEach(overlay => {
            overlay.style.display = 'none';
        });
        document.getElementById(id).style.display = 'flex';
    }

    hideOverlays() {
        document.querySelectorAll('.overlay').forEach(overlay => {
            overlay.style.display = 'none';
        });
    }
}

// 初始化游戏
window.addEventListener('load', () => {
    new Game();
});
