// 贪吃蛇游戏 - Snake Game
// 感性编程，让代码充满温度 ❤️

// 游戏配置
const CONFIG = {
    gridSize: 20,
    initialSpeed: 150,
    speedIncrement: 2,
    minSpeed: 50,
    colors: {
        snakeHead: '#667eea',
        snakeBody: '#764ba2',
        food: '#ff6b6b',
        grid: '#e0e0e0',
        background: '#f0f0f0'
    }
};

// 游戏状态
let gameState = {
    snake: [],
    direction: { x: 1, y: 0 },
    nextDirection: { x: 1, y: 0 },
    food: { x: 0, y: 0 },
    score: 0,
    highScore: localStorage.getItem('snakeHighScore') || 0,
    gameSpeed: CONFIG.initialSpeed,
    isRunning: false,
    isPaused: false,
    gameLoop: null
};

// DOM 元素
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');
const scoreEl = document.getElementById('score');
const highScoreEl = document.getElementById('highScore');
const snakeLengthEl = document.getElementById('snakeLength');
const finalScoreEl = document.getElementById('finalScore');

// 初始化游戏
function initGame() {
    const cols = canvas.width / CONFIG.gridSize;
    const rows = canvas.height / CONFIG.gridSize;

    // 初始化蛇（3节）
    gameState.snake = [
        { x: Math.floor(cols / 2), y: Math.floor(rows / 2) },
        { x: Math.floor(cols / 2) - 1, y: Math.floor(rows / 2) },
        { x: Math.floor(cols / 2) - 2, y: Math.floor(rows / 2) }
    ];

    gameState.direction = { x: 1, y: 0 };
    gameState.nextDirection = { x: 1, y: 0 };
    gameState.score = 0;
    gameState.gameSpeed = CONFIG.initialSpeed;
    gameState.isRunning = true;
    gameState.isPaused = false;

    updateScore();
    spawnFood();
    draw();
}

// 生成食物
function spawnFood() {
    const cols = canvas.width / CONFIG.gridSize;
    const rows = canvas.height / CONFIG.gridSize;

    let validPosition = false;
    let food;

    while (!validPosition) {
        food = {
            x: Math.floor(Math.random() * cols),
            y: Math.floor(Math.random() * rows)
        };

        // 确保食物不在蛇身上
        validPosition = !gameState.snake.some(segment => 
            segment.x === food.x && segment.y === food.y
        );
    }

    gameState.food = food;
}

// 绘制游戏
function draw() {
    // 清空画布
    ctx.fillStyle = CONFIG.colors.background;
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    // 绘制网格线（淡淡的，像记忆的痕迹）
    ctx.strokeStyle = CONFIG.colors.grid;
    ctx.lineWidth = 1;

    for (let x = 0; x <= canvas.width; x += CONFIG.gridSize) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, canvas.height);
        ctx.stroke();
    }

    for (let y = 0; y <= canvas.height; y += CONFIG.gridSize) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(canvas.width, y);
        ctx.stroke();
    }

    // 绘制食物（像一颗红宝石✨）
    const foodX = gameState.food.x * CONFIG.gridSize + CONFIG.gridSize / 2;
    const foodY = gameState.food.y * CONFIG.gridSize + CONFIG.gridSize / 2;

    ctx.fillStyle = CONFIG.colors.food;
    ctx.beginPath();
    ctx.arc(foodX, foodY, CONFIG.gridSize / 2 - 2, 0, Math.PI * 2);
    ctx.fill();

    // 绘制蛇
    gameState.snake.forEach((segment, index) => {
        const x = segment.x * CONFIG.gridSize;
        const y = segment.y * CONFIG.gridSize;

        // 蛇头和身体颜色不同
        ctx.fillStyle = index === 0 ? CONFIG.colors.snakeHead : CONFIG.colors.snakeBody;

        // 圆角矩形
        const radius = 3;
        ctx.beginPath();
        ctx.roundRect(x + 1, y + 1, CONFIG.gridSize - 2, CONFIG.gridSize - 2, radius);
        ctx.fill();

        // 蛇头的眼睛
        if (index === 0) {
            ctx.fillStyle = 'white';

            // 根据方向绘制眼睛
            const eyeOffset = CONFIG.gridSize / 4;
            const eyeSize = 3;

            if (gameState.direction.x === 1) { // 向右
                ctx.beginPath();
                ctx.arc(x + CONFIG.gridSize - eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.arc(x + CONFIG.gridSize - eyeOffset, y + CONFIG.gridSize - eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            } else if (gameState.direction.x === -1) { // 向左
                ctx.beginPath();
                ctx.arc(x + eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.arc(x + eyeOffset, y + CONFIG.gridSize - eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            } else if (gameState.direction.y === -1) { // 向上
                ctx.beginPath();
                ctx.arc(x + eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.arc(x + CONFIG.gridSize - eyeOffset, y + eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            } else { // 向下
                ctx.beginPath();
                ctx.arc(x + eyeOffset, y + CONFIG.gridSize - eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.arc(x + CONFIG.gridSize - eyeOffset, y + CONFIG.gridSize - eyeOffset, eyeSize, 0, Math.PI * 2);
                ctx.fill();
            }
        }
    });

    // 更新UI
    snakeLengthEl.textContent = gameState.snake.length;
}

// 移动蛇
function moveSnake() {
    gameState.direction = gameState.nextDirection;

    const head = {
        x: gameState.snake[0].x + gameState.direction.x,
        y: gameState.snake[0].y + gameState.direction.y
    };

    // 检查碰撞
    if (checkCollision(head)) {
        gameOver();
        return;
    }

    gameState.snake.unshift(head);

    // 检查是否吃到食物
    if (head.x === gameState.food.x && head.y === gameState.food.y) {
        gameState.score += 10;
        updateScore();
        spawnFood();

        // 加速游戏
        if (gameState.gameSpeed > CONFIG.minSpeed) {
            gameState.gameSpeed -= CONFIG.speedIncrement;
        }
    } else {
        gameState.snake.pop();
    }

    draw();
}

// 检查碰撞
function checkCollision(position) {
    const cols = canvas.width / CONFIG.gridSize;
    const rows = canvas.height / CONFIG.gridSize;

    // 撞墙
    if (position.x < 0 || position.x >= cols || 
        position.y < 0 || position.y >= rows) {
        return true;
    }

    // 撞自己
    for (let i = 1; i < gameState.snake.length; i++) {
        if (position.x === gameState.snake[i].x && 
            position.y === gameState.snake[i].y) {
            return true;
        }
    }

    return false;
}

// 更新分数
function updateScore() {
    scoreEl.textContent = gameState.score;

    if (gameState.score > gameState.highScore) {
        gameState.highScore = gameState.score;
        localStorage.setItem('snakeHighScore', gameState.highScore);
    }

    highScoreEl.textContent = gameState.highScore;
}

// 游戏结束
function gameOver() {
    gameState.isRunning = false;
    clearInterval(gameState.gameLoop);

    finalScoreEl.textContent = gameState.score;
    document.getElementById('gameOverScreen').style.display = 'flex';
}

// 游戏循环
function gameLoop() {
    if (!gameState.isPaused) {
        moveSnake();
    }
}

// 键盘控制
document.addEventListener('keydown', (e) => {
    if (!gameState.isRunning) return;

    switch (e.key) {
        case 'ArrowUp':
            if (gameState.direction.y === 0) {
                gameState.nextDirection = { x: 0, y: -1 };
            }
            e.preventDefault();
            break;
        case 'ArrowDown':
            if (gameState.direction.y === 0) {
                gameState.nextDirection = { x: 0, y: 1 };
            }
            e.preventDefault();
            break;
        case 'ArrowLeft':
            if (gameState.direction.x === 0) {
                gameState.nextDirection = { x: -1, y: 0 };
            }
            e.preventDefault();
            break;
        case 'ArrowRight':
            if (gameState.direction.x === 0) {
                gameState.nextDirection = { x: 1, y: 0 };
            }
            e.preventDefault();
            break;
        case ' ':
            togglePause();
            e.preventDefault();
            break;
        case 'Enter':
            if (!gameState.isRunning) {
                startGame();
            }
            break;
    }
});

// 暂停/继续
function togglePause() {
    if (!gameState.isRunning) return;

    gameState.isPaused = !gameState.isPaused;

    if (gameState.isPaused) {
        document.getElementById('pauseScreen').style.display = 'flex';
    } else {
        document.getElementById('pauseScreen').style.display = 'none';
    }
}

