    // 移动蛇
    if (dx !== 0 || dy !== 0) {
        const head = {x: snake[0].x + dx, y: snake[0].y + dy};

        // 检查碰撞
        if (head.x < 0 || head.x >= tileCount || head.y < 0 || head.y >= tileCount || checkSelfCollision(head)) {
            gameOver();
            return;
        }

        snake.unshift(head);

        // 检查是否吃到食物
        if (head.x === food.x && head.y === food.y) {
            score += 10;
            scoreElement.textContent = score;
            placeFood();
        } else {
            snake.pop();
        }
